#include <stdio.h>
#include <stdbool.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        unsigned long long M, N;
        scanf("%llu %llu", &M, &N);
        unsigned long long odd = M;
        while ((odd & 1ULL) == 0ULL) odd >>= 1ULL; // remove factors of 2
        if (N <= M && N % odd == 0ULL) {
            puts("YES");
        } else {
            puts("NO");
        }
    }
    return 0;
}

