#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        M = int(next(it))
        N = int(next(it))
        odd = M
        while odd % 2 == 0:
            odd //= 2
        if N <= M and N % odd == 0:
            out_lines.append("YES")
        else:
            out_lines.append("NO")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    main()

